import{_ as a,o as s,c as n,a4 as t}from"./chunks/framework.BIesbIg_.js";const u=JSON.parse('{"title":"Syntax Cheatsheet","description":"","frontmatter":{},"headers":[],"relativePath":"reference/cheatsheet.md","filePath":"reference/cheatsheet.md"}'),l={name:"reference/cheatsheet.md"};function p(i,e,o,d,c,r){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="syntax-cheatsheet" tabindex="-1">Syntax Cheatsheet <a class="header-anchor" href="#syntax-cheatsheet" aria-label="Permalink to &quot;Syntax Cheatsheet&quot;">​</a></h1><p>Quick reference for GCF encoding. Every example is a complete, valid GCF fragment.</p><h2 id="header" tabindex="-1">Header <a class="header-anchor" href="#header" aria-label="Permalink to &quot;Header&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GCF tool=&lt;name&gt; budget=&lt;int&gt; tokens=&lt;int&gt; symbols=&lt;int&gt; pack_root=&lt;hex&gt;</span></span></code></pre></div><p>Only <code>tool</code> is required. All other fields are optional.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GCF tool=context_for_task</span></span>
<span class="line"><span>GCF tool=context_for_task budget=5000 tokens=1847 symbols=10</span></span>
<span class="line"><span>GCF tool=context_for_task budget=5000 tokens=1847 symbols=10 pack_root=a1b2c3d4</span></span>
<span class="line"><span>GCF tool=context_for_task tokens=800 symbols=5 session=true</span></span>
<span class="line"><span>GCF tool=context_for_task delta=true base_root=aaa111 new_root=bbb222 tokens=30 savings=81%</span></span></code></pre></div><h2 id="symbol-lines" tabindex="-1">Symbol lines <a class="header-anchor" href="#symbol-lines" aria-label="Permalink to &quot;Symbol lines&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@{id} {kind} {qualified_name} {score} {provenance}</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@0 fn github.com/org/repo/pkg.AuthMiddleware 0.78 lsp_resolved</span></span>
<span class="line"><span>@1 type github.com/org/repo/pkg.Config 0.65 ast_inferred</span></span>
<span class="line"><span>@2 method github.com/org/repo/pkg.Server.Start 0.54 lsp_resolved</span></span>
<span class="line"><span>@3 iface github.com/org/repo/pkg.Handler 0.48 structural</span></span>
<span class="line"><span>@4 var github.com/org/repo/pkg.DefaultTimeout 0.32 ast_inferred</span></span></code></pre></div><ul><li><code>id</code>: zero-based integer, sequential</li><li><code>kind</code>: abbreviated (see table below)</li><li><code>qualified_name</code>: no whitespace allowed</li><li><code>score</code>: 2 decimal places (e.g., <code>0.78</code>)</li><li><code>provenance</code>: no whitespace allowed</li></ul><h2 id="edge-lines" tabindex="-1">Edge lines <a class="header-anchor" href="#edge-lines" aria-label="Permalink to &quot;Edge lines&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@{target}&lt;@{source} {edge_type} [{status}]</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@0&lt;@2 calls              # @2 calls @0</span></span>
<span class="line"><span>@1&lt;@0 references         # @0 references @1</span></span>
<span class="line"><span>@3&lt;@2 implements         # @2 implements @3</span></span>
<span class="line"><span>@0&lt;@4 calls added        # new edge (diff payload)</span></span>
<span class="line"><span>@1&lt;@3 imports removed    # deleted edge (diff payload)</span></span></code></pre></div><ul><li><code>&lt;</code> arrow points toward target</li><li>Status is optional: <code>added</code> or <code>removed</code> (omit for normal payloads)</li></ul><h2 id="group-headers" tabindex="-1">Group headers <a class="header-anchor" href="#group-headers" aria-label="Permalink to &quot;Group headers&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## targets       # distance 0 (direct matches)</span></span>
<span class="line"><span>## related       # distance 1 (one hop)</span></span>
<span class="line"><span>## extended      # distance 2 (broader context)</span></span>
<span class="line"><span>## distance_5    # explicit distance N</span></span>
<span class="line"><span>## edges         # relationship section</span></span></code></pre></div><h2 id="kind-abbreviations" tabindex="-1">Kind abbreviations <a class="header-anchor" href="#kind-abbreviations" aria-label="Permalink to &quot;Kind abbreviations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Short</th><th>Full</th><th>Short</th><th>Full</th></tr></thead><tbody><tr><td><code>fn</code></td><td>function</td><td><code>table</code></td><td>table</td></tr><tr><td><code>type</code></td><td>type</td><td><code>resource</code></td><td>resource</td></tr><tr><td><code>method</code></td><td>method</td><td><code>class</code></td><td>class</td></tr><tr><td><code>iface</code></td><td>interface</td><td><code>selector</code></td><td>selector</td></tr><tr><td><code>var</code></td><td>var</td><td><code>field</code></td><td>field</td></tr><tr><td><code>const</code></td><td>const</td><td><code>route</code></td><td>route_handler</td></tr><tr><td><code>file</code></td><td>file</td><td><code>ext</code></td><td>external</td></tr><tr><td><code>pkg</code></td><td>package</td><td><code>svc</code></td><td>service</td></tr></tbody></table><p>Unknown kinds pass through verbatim.</p><h2 id="session-bare-references" tabindex="-1">Session bare references <a class="header-anchor" href="#session-bare-references" aria-label="Permalink to &quot;Session bare references&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@7  # previously transmitted</span></span></code></pre></div><p>Two spaces before <code>#</code>. Used when <code>session=true</code> in header.</p><h2 id="delta-payload" tabindex="-1">Delta payload <a class="header-anchor" href="#delta-payload" aria-label="Permalink to &quot;Delta payload&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GCF tool=context_for_task delta=true base_root=aaa new_root=bbb tokens=30 savings=85%</span></span>
<span class="line"><span>## removed</span></span>
<span class="line"><span>fn pkg.OldFunc</span></span>
<span class="line"><span>method pkg.Server.Deprecated</span></span>
<span class="line"><span>## added</span></span>
<span class="line"><span>@0 fn pkg.NewFunc 0.85 rwr</span></span>
<span class="line"><span>@1 type pkg.NewConfig 0.72 ast_inferred</span></span>
<span class="line"><span>## edges_removed</span></span>
<span class="line"><span>pkg.Router -&gt; pkg.OldFunc calls</span></span>
<span class="line"><span>## edges_added</span></span>
<span class="line"><span>pkg.Router -&gt; pkg.NewFunc calls</span></span></code></pre></div><ul><li><code>## removed</code>: kind + qname only (consumer has full declaration from prior response)</li><li><code>## added</code>: full symbol lines with sequential IDs from 0</li><li><code>## edges_removed</code> / <code>## edges_added</code>: <code>source -&gt; target type</code> format</li></ul><h2 id="tabular-encoding-generic-profile" tabindex="-1">Tabular encoding (generic profile) <a class="header-anchor" href="#tabular-encoding-generic-profile" aria-label="Permalink to &quot;Tabular encoding (generic profile)&quot;">​</a></h2><h3 id="tabular-array" tabindex="-1">Tabular array <a class="header-anchor" href="#tabular-array" aria-label="Permalink to &quot;Tabular array&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## {name} [{count}]{{field1},{field2},{field3}}</span></span>
<span class="line"><span>value1|value2|value3</span></span>
<span class="line"><span>value1|value2|value3</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## employees [3]{id,name,department,salary}</span></span>
<span class="line"><span>1|Alice Smith|Engineering|95000</span></span>
<span class="line"><span>2|Bob Jones|Sales|72000</span></span>
<span class="line"><span>3|Carol Wu|Marketing|85000</span></span></code></pre></div><ul><li>One header declares field names; rows are positional values only</li><li>Pipe <code>|</code> separator, no spaces</li><li>No <code>@id</code> on flat rows (only when nested fields need cross-referencing)</li></ul><h3 id="tabular-with-nested-fields" tabindex="-1">Tabular with nested fields <a class="header-anchor" href="#tabular-with-nested-fields" aria-label="Permalink to &quot;Tabular with nested fields&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## orders [2]{id,total,status}</span></span>
<span class="line"><span>@0 1001|249.99|shipped</span></span>
<span class="line"><span>  .customer</span></span>
<span class="line"><span>    name=Alice Smith</span></span>
<span class="line"><span>    tier=premium</span></span>
<span class="line"><span>@1 1002|89.50|pending</span></span>
<span class="line"><span>  .customer</span></span>
<span class="line"><span>    name=Bob Jones</span></span>
<span class="line"><span>    tier=standard</span></span></code></pre></div><ul><li><code>@{id}</code> prefix when rows have nested sub-objects</li><li><code>.fieldname</code> introduces an inline nested object</li><li>Nested fields use <code>key=value</code> pairs, indented</li></ul><h3 id="object-encoding" tabindex="-1">Object encoding <a class="header-anchor" href="#object-encoding" aria-label="Permalink to &quot;Object encoding&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>config=production</span></span>
<span class="line"><span>version=2.1.0</span></span>
<span class="line"><span>## database</span></span>
<span class="line"><span>  host=db.example.com</span></span>
<span class="line"><span>  port=5432</span></span>
<span class="line"><span>  pool_size=10</span></span></code></pre></div><ul><li>Primitives: <code>key=value</code> (no quotes for numbers/booleans)</li><li>Nested objects: <code>## key</code> section header + indented key=value</li><li>Null/missing: <code>-</code></li></ul><h3 id="value-formatting" tabindex="-1">Value formatting <a class="header-anchor" href="#value-formatting" aria-label="Permalink to &quot;Value formatting&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Format</th><th>Example</th></tr></thead><tbody><tr><td>String</td><td>bare text</td><td><code>Alice Smith</code></td></tr><tr><td>Number</td><td>unquoted</td><td><code>95000</code></td></tr><tr><td>Boolean</td><td>lowercase</td><td><code>true</code> / <code>false</code></td></tr><tr><td>Null</td><td>dash</td><td><code>-</code></td></tr><tr><td>String with <code>|</code> or newline</td><td>quoted</td><td><code>&quot;value|with|pipes&quot;</code></td></tr></tbody></table><h2 id="comments" tabindex="-1">Comments <a class="header-anchor" href="#comments" aria-label="Permalink to &quot;Comments&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># This is a comment (ignored by parsers)</span></span></code></pre></div><p>Must start with <code># </code> (hash + space). Group headers (<code>##</code>) are NOT comments.</p><h2 id="complete-examples" tabindex="-1">Complete examples <a class="header-anchor" href="#complete-examples" aria-label="Permalink to &quot;Complete examples&quot;">​</a></h2><h3 id="graph-profile" tabindex="-1">Graph profile <a class="header-anchor" href="#graph-profile" aria-label="Permalink to &quot;Graph profile&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GCF tool=context_for_task budget=5000 tokens=1847 symbols=5 pack_root=a1b2c3d4</span></span>
<span class="line"><span>## targets</span></span>
<span class="line"><span>@0 fn github.com/org/repo/internal/auth.Middleware 0.78 lsp_resolved</span></span>
<span class="line"><span>@1 type github.com/org/repo/internal/auth.Config 0.71 ast_inferred</span></span>
<span class="line"><span>## related</span></span>
<span class="line"><span>@2 fn github.com/org/repo/internal/server.New 0.54 lsp_resolved</span></span>
<span class="line"><span>@3 method github.com/org/repo/internal/server.Server.Start 0.48 lsp_resolved</span></span>
<span class="line"><span>## extended</span></span>
<span class="line"><span>@4 iface github.com/org/repo/internal/handler.Handler 0.32 structural</span></span>
<span class="line"><span>## edges</span></span>
<span class="line"><span>@0&lt;@2 calls</span></span>
<span class="line"><span>@1&lt;@0 references</span></span>
<span class="line"><span>@4&lt;@2 implements</span></span>
<span class="line"><span>@3&lt;@2 calls</span></span></code></pre></div><h3 id="tabular-profile" tabindex="-1">Tabular profile <a class="header-anchor" href="#tabular-profile" aria-label="Permalink to &quot;Tabular profile&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>name=Acme Corp</span></span>
<span class="line"><span>region=us-east-1</span></span>
<span class="line"><span>## employees [3]{id,name,department,salary,active}</span></span>
<span class="line"><span>1|Alice Smith|Engineering|95000|true</span></span>
<span class="line"><span>2|Bob Jones|Sales|72000|true</span></span>
<span class="line"><span>3|Carol Wu|Marketing|85000|false</span></span>
<span class="line"><span>## projects [2]{id,title,lead}</span></span>
<span class="line"><span>@0 101|Auth Rewrite|Alice Smith</span></span>
<span class="line"><span>  .tags</span></span>
<span class="line"><span>    priority=high</span></span>
<span class="line"><span>    deadline=2026-Q3</span></span>
<span class="line"><span>@1 102|Dashboard|Bob Jones</span></span>
<span class="line"><span>  .tags</span></span>
<span class="line"><span>    priority=medium</span></span>
<span class="line"><span>    deadline=2026-Q4</span></span></code></pre></div>`,46)])])}const b=a(l,[["render",p]]);export{u as __pageData,b as default};
